// RegisterTools registers all API operations as MCP tools.
func RegisterTools(s *server.MCPServer) {
	// Code-orchestration mode — the full surface is covered by two tools
	// (<api>_search + <api>_execute). Endpoint-mirror tools are suppressed.
	RegisterCodeOrchestrationTools(s)

	// Context tool — front-loaded domain knowledge for agents.
	// Call this first to understand the API taxonomy, query patterns, and capabilities.
	s.AddTool(
		mcplib.NewTool("context",
			mcplib.WithDescription("Get API domain context: resource taxonomy, auth requirements, query tips, and unique capabilities. Returns object with auth setup, resource list, and query patterns. Call this first."),
			mcplib.WithReadOnlyHintAnnotation(true),
			mcplib.WithDestructiveHintAnnotation(false),
		),
		handleContext,
	)

	// Cross-resource full-text search over the local SQLite cache.
	// Returns array of matching items and recipes. Requires sync to have been run.
	s.AddTool(
		mcplib.NewTool("search",
			mcplib.WithDescription("Full-text search across all AnyList data (items, recipes). Returns array of matches with resource type and name. Requires sync — run 'anylist-pp-cli sync' first to populate the local cache."),
			mcplib.WithString("query", mcplib.Required(), mcplib.Description("Search query string.")),
			mcplib.WithReadOnlyHintAnnotation(true),
		),
		handleSearch,
	)

	// Runtime Cobra-tree mirror — exposes every user-facing command that is
	// not already covered by a typed endpoint or framework MCP tool.
	cobratree.RegisterAll(s, cli.RootCmd(), cobratree.SiblingCLIPath)
}

