// handleSearch performs full-text search across items and recipes in the local
// SQLite cache. Returns array of {type, name, ...} matches.
func handleSearch(_ context.Context, req mcplib.CallToolRequest) (*mcplib.CallToolResult, error) {
	args := req.GetArguments()
	query, _ := args["query"].(string)
	if strings.TrimSpace(query) == "" {
		return mcplib.NewToolResultError("query is required"), nil
	}

	home, _ := os.UserHomeDir()
	cfgPath := filepath.Join(home, ".config", "anylist-pp-cli", "config.toml")
	cfg, err := config.Load(cfgPath)
	if err != nil {
		return mcplib.NewToolResultError("config load: " + err.Error()), nil
	}
	st, err := store.Open(cfg)
	if err != nil {
		return mcplib.NewToolResultError("store open failed — run 'anylist-pp-cli sync' first: " + err.Error()), nil
	}
	defer st.Close()

	var results []map[string]any

	items, _ := st.SearchItems(query)
	for _, it := range items {
		results = append(results, map[string]any{
			"type":     "item",
			"name":     it.Name,
			"list":     it.ListName,
			"quantity": it.Quantity,
			"checked":  it.Checked,
		})
	}

	recipes, _ := st.SearchRecipesByName(query)
	for _, r := range recipes {
		results = append(results, map[string]any{
			"type":   "recipe",
			"name":   r.Name,
			"rating": r.Rating,
			"note":   r.Note,
		})
	}

	out, _ := json.Marshal(map[string]any{"count": len(results), "results": results})
	return mcplib.NewToolResultText(string(out)), nil
}

